  1→import { useCallback, useRef, useState, useEffect } from "react";
  2→import {
  3→  ReactFlow,
  4→  MiniMap,
  5→  Controls,
  6→  Background,
  7→  useReactFlow,
  8→  ReactFlowProvider,
  9→  applyNodeChanges,
 10→  applyEdgeChanges,
 11→  type Node,
 12→  type Edge,
 13→  type OnNodesChange,
 14→  type OnEdgesChange,
 15→  type OnConnect,
 16→  type Connection,
 17→  type NodeTypes,
 18→  type EdgeTypes,
 19→} from "@xyflow/react";
 20→import "@xyflow/react/dist/style.css";
 21→
 22→import { NodeCard, type NodeCardData } from "./NodeCard";
 23→import { EdgeWithCondition, type EdgeConditionData } from "./EdgeWithCondition";
 24→import { type PortType, type NodeDefinition } from "@/lib/types";
 25→
 26→// ── Port-type validation (pure function) ─────────────────────────────
 27→
 28→export function arePortTypesCompatible(
 29→  sourceType: PortType | undefined,
 30→  targetType: PortType | undefined,
 31→): boolean {
 32→  if (!sourceType || !targetType) return false;
 33→  return sourceType === targetType;
 34→}
 35→
 36→// ── Custom node / edge types ─────────────────────────────────────────
 37→
 38→const nodeTypes: NodeTypes = {
 39→  nodeCard: NodeCard,
 40→};
 41→
 42→const edgeTypes: EdgeTypes = {
 43→  edgeWithCondition: EdgeWithCondition,
 44→};
 45→
 46→// ── History for undo/redo ────────────────────────────────────────────
 47→
 48→interface CanvasSnapshot {
 49→  nodes: Node<NodeCardData>[];
 50→  edges: Edge[];
 51→}
 52→
 53→function useHistory(initial: CanvasSnapshot) {
 54→  const stack = useRef<CanvasSnapshot[]>([initial]);
 55→  const pointer = useRef(0);
 56→
 57→  const push = useCallback((snapshot: CanvasSnapshot) => {
 58→    stack.current = stack.current.slice(0, pointer.current + 1);
 59→    stack.current.push(snapshot);
 60→    pointer.current = stack.current.length - 1;
 61→  }, []);
 62→
 63→  const undo = useCallback((): CanvasSnapshot | null => {
 64→    if (pointer.current > 0) {
 65→      pointer.current -= 1;
 66→      return stack.current[pointer.current] ?? null;
 67→    }
 68→    return null;
 69→  }, []);
 70→
 71→  const redo = useCallback((): CanvasSnapshot | null => {
 72→    if (pointer.current < stack.current.length - 1) {
 73→      pointer.current += 1;
 74→      return stack.current[pointer.current] ?? null;
 75→    }
 76→    return null;
 77→  }, []);
 78→
 79→  return { push, undo, redo };
 80→}
 81→
 82→// ── Canvas inner (needs ReactFlowProvider) ───────────────────────────
 83→
 84→export interface CanvasProps {
 85→  nodes?: Node<NodeCardData>[];
 86→  edges?: Edge[];
 87→  onNodesChange?: OnNodesChange<Node<NodeCardData>>;
 88→  onEdgesChange?: OnEdgesChange;
 89→  onConnect?: OnConnect;
 90→  onNodeSelect?: (nodeId?: string, tab?: string) => void;
 91→}
 92→
 93→let nodeIdCounter = 0;
 94→
 95→function CanvasInner({
 96→  nodes: controlledNodes,
 97→  edges: controlledEdges,
 98→  onNodesChange: controlledOnNodesChange,
 99→  onEdgesChange: controlledOnEdgesChange,
100→  onConnect: controlledOnConnect,
101→  onNodeSelect,
102→}: CanvasProps) {
103→  const isControlled = controlledNodes !== undefined;
104→
105→  const [internalNodes, setInternalNodes] = useState<Node<NodeCardData>[]>([]);
106→  const [internalEdges, setInternalEdges] = useState<Edge[]>([]);
107→
108→  const nodes = isControlled ? controlledNodes : internalNodes;
109→  const edges = isControlled ? (controlledEdges ?? []) : internalEdges;
110→
111→  const { screenToFlowPosition } = useReactFlow();
112→  const history = useHistory({ nodes: [], edges: [] });
113→
114→  // Push snapshot to history for undo
115→  const pushHistory = useCallback(
116→    (n: Node<NodeCardData>[], e: Edge[]) => {
117→      history.push({ nodes: n, edges: e });
118→    },
119→    [history],
120→  );
121→
122→  // ── Node / edge change handlers ──────────────────────────────────
123→
124→  const onNodesChange: OnNodesChange<Node<NodeCardData>> = useCallback(
125→    (changes) => {
126→      if (isControlled) {
127→        controlledOnNodesChange?.(changes);
128→        return;
129→      }
130→      setInternalNodes((nds) => {
131→        const next = applyNodeChanges(changes, nds);
132→        // Push history on remove
133→        const hasRemove = changes.some((c) => c.type === "remove");
134→        if (hasRemove) {
135→          // edges may also change, but we push current edges
136→          pushHistory(next, internalEdges);
137→        }
138→        return next;
139→      });
140→    },
141→    [isControlled, controlledOnNodesChange, pushHistory, internalEdges],
142→  );
143→
144→  const onEdgesChange: OnEdgesChange = useCallback(
145→    (changes) => {
146→      if (isControlled) {
147→        controlledOnEdgesChange?.(changes);
148→        return;
149→      }
150→      setInternalEdges((eds) => {
151→        const next = applyEdgeChanges(changes, eds);
152→        const hasRemove = changes.some((c) => c.type === "remove");
153→        if (hasRemove) {
154→          pushHistory(internalNodes, next);
155→        }
156→        return next;
157→      });
158→    },
159→    [isControlled, controlledOnEdgesChange, pushHistory, internalNodes],
160→  );
161→
162→  // ── Connect handler with port-type validation ────────────────────
163→
164→  const onConnect: OnConnect = useCallback(
165→    (connection: Connection) => {
166→      if (isControlled) {
167→        controlledOnConnect?.(connection);
168→        return;
169→      }
170→
171→      const sourceNode = internalNodes.find((n) => n.id === connection.source);
172→      const targetNode = internalNodes.find((n) => n.id === connection.target);
173→
174→      const sourcePort = sourceNode?.data?.definition?.outputs?.find(
175→        (p) => p.name === connection.sourceHandle,
176→      );
177→      const targetPort = targetNode?.data?.definition?.inputs?.find(
178→        (p) => p.name === connection.targetHandle,
179→      );
180→
181→      if (!arePortTypesCompatible(sourcePort?.type, targetPort?.type)) {
182→        // Flash the target handle red
183→        const handleEl = document.querySelector(
184→          `.react-flow__handle[data-handleid="${connection.targetHandle}"][data-nodeid="${connection.target}"]`,
185→        );
186→        if (handleEl) {
187→          handleEl.classList.add("handle-flash-red");
188→          setTimeout(() => handleEl.classList.remove("handle-flash-red"), 600);
189→        }
190→        return;
191→      }
192→
193→      const newEdge: Edge = {
194→        id: `e-${connection.source}-${connection.sourceHandle}-${connection.target}-${connection.targetHandle}`,
195→        source: connection.source!,
196→        sourceHandle: connection.sourceHandle,
197→        target: connection.target!,
198→        targetHandle: connection.targetHandle,
199→        type: "edgeWithCondition",
200→      };
201→
202→      setInternalEdges((eds) => {
203→        const next = [...eds, newEdge];
204→        pushHistory(internalNodes, next);
205→        return next;
206→      });
207→    },
208→    [isControlled, controlledOnConnect, internalNodes, pushHistory],
209→  );
210→
211→  // ── Edge condition change handler ──────────────────────────────────
212→
213→  const onConditionChange = useCallback(
214→    (edgeId: string, condition: string) => {
215→      if (isControlled) return;
216→      setInternalEdges((eds) =>
217→        eds.map((e) =>
218→          e.id === edgeId
219→            ? { ...e, data: { ...e.data, condition } }
220→            : e,
221→        ),
222→      );
223→    },
224→    [isControlled],
225→  );
226→
227→  // Inject onConditionChange and ensure custom edge type on all edges
228→  const edgesWithCallbacks = edges.map((edge) => ({
229→    ...edge,
230→    type: edge.type || "edgeWithCondition",
231→    data: {
232→      ...edge.data,
233→      onConditionChange,
234→    } as EdgeConditionData,
235→  }));
236→
237→  // ── Node drag end → push history ─────────────────────────────────
238→
239→  const onNodeDragStop = useCallback(() => {
240→    if (!isControlled) {
241→      // Defer to capture the updated node positions
242→      setTimeout(() => {
243→        setInternalNodes((nds) => {
244→          pushHistory(nds, internalEdges);
245→          return nds;
246→        });
247→      }, 0);
248→    }
249→  }, [isControlled, pushHistory, internalEdges]);
250→
251→  // ── Tab click handler (passed to each node via data) ─────────────
252→
253→  const handleTabClick = useCallback(
254→    (nodeId: string, tab: string) => {
255→      onNodeSelect?.(nodeId, tab);
256→    },
257→    [onNodeSelect],
258→  );
259→
260→  // Inject onTabClick into node data
261→  const nodesWithCallbacks = nodes.map((node) => ({
262→    ...node,
263→    data: {
264→      ...node.data,
265→      onTabClick: handleTabClick,
266→    },
267→  }));
268→
269→  // ── Keyboard shortcuts ───────────────────────────────────────────
270→
271→  useEffect(() => {
272→    const handler = (e: KeyboardEvent) => {
273→      // Undo: Ctrl+Z (without shift)
274→      if (e.key === "z" && (e.ctrlKey || e.metaKey) && !e.shiftKey) {
275→        e.preventDefault();
276→        const snapshot = history.undo();
277→        if (snapshot && !isControlled) {
278→          setInternalNodes(snapshot.nodes);
279→          setInternalEdges(snapshot.edges);
280→        }
281→      }
282→      // Redo: Ctrl+Shift+Z
283→      if (e.key === "z" && (e.ctrlKey || e.metaKey) && e.shiftKey) {
284→        e.preventDefault();
285→        const snapshot = history.redo();
286→        if (snapshot && !isControlled) {
287→          setInternalNodes(snapshot.nodes);
288→          setInternalEdges(snapshot.edges);
289→        }
290→      }
291→    };
292→
293→    window.addEventListener("keydown", handler);
294→    return () => window.removeEventListener("keydown", handler);
295→  }, [history, isControlled]);
296→
297→  // ── Drag-and-drop from sidebar ───────────────────────────────────
298→
299→  const onDragOver = useCallback((event: React.DragEvent) => {
300→    event.preventDefault();
301→    event.dataTransfer.dropEffect = "move";
302→  }, []);
303→
304→  const onDrop = useCallback(
305→    (event: React.DragEvent) => {
306→      event.preventDefault();
307→      const raw = event.dataTransfer.getData("application/reactflow");
308→      if (!raw) return;
309→
310→      let definition: NodeDefinition;
311→      try {
312→        definition = JSON.parse(raw);
313→      } catch {
314→        return;
315→      }
316→
317→      const position = screenToFlowPosition({
318→        x: event.clientX,
319→        y: event.clientY,
320→      });
321→
322→      nodeIdCounter += 1;
323→      const newNodeId = `node-${Date.now()}-${nodeIdCounter}`;
324→
325→      // Build default params from definition
326→      const defaultParams: Record<string, string | number | boolean> = {};
327→      for (const p of definition.params) {
328→        defaultParams[p.name] = p.default;
329→      }
330→
331→      const newNode: Node<NodeCardData> = {
332→        id: newNodeId,
333→        type: "nodeCard",
334→        position,
335→        data: {
336→          label: definition.label,
337→          definition,
338→          status: "idle",
339→          params: defaultParams,
340→        },
341→      };
342→
343→      if (isControlled) {
344→        // In controlled mode, the parent handles adding nodes
345→        return;
346→      }
347→
348→      setInternalNodes((nds) => {
349→        const next = [...nds, newNode];
350→        pushHistory(next, internalEdges);
351→        return next;
352→      });
353→    },
354→    [screenToFlowPosition, isControlled, pushHistory, internalEdges],
355→  );
356→
357→  return (
358→    <div className="h-full w-full" onDragOver={onDragOver} onDrop={onDrop}>
359→      <ReactFlow
360→        nodes={nodesWithCallbacks}
361→        edges={edgesWithCallbacks}
362→        onNodesChange={onNodesChange}
363→        onEdgesChange={onEdgesChange}
364→        onConnect={onConnect}
365→        onNodeDragStop={onNodeDragStop}
366→        nodeTypes={nodeTypes}
367→        edgeTypes={edgeTypes}
368→        deleteKeyCode="Delete"
369→        fitView
370→        className="bg-[#1a1a1e]"
371→      >
372→        <Background color="#333" gap={20} />
373→        <Controls className="!bg-[#27272a] !border-[#3f3f46] !rounded-lg [&>button]:!bg-[#27272a] [&>button]:!border-[#3f3f46] [&>button]:!fill-[#a1a1aa] [&>button:hover]:!bg-[#3f3f46]" />
374→        <MiniMap
375→          position="bottom-right"
376→          className="!bg-[#27272a] !border-[#3f3f46] !rounded-lg"
377→          maskColor="rgba(0,0,0,0.5)"
378→          nodeColor="#3B82F6"
379→        />
380→      </ReactFlow>
381→    </div>
382→  );
383→}
384→
385→// ── Wrapped export with ReactFlowProvider ────────────────────────────
386→
387→export function Canvas(props: CanvasProps) {
388→  return (
389→    <ReactFlowProvider>
390→      <CanvasInner {...props} />
391→    </ReactFlowProvider>
392→  );
393→}
