  1→import { useState, useCallback, useRef, useEffect } from "react";
  2→import {
  3→  getBezierPath,
  4→  BaseEdge,
  5→  type EdgeProps,
  6→  type Edge,
  7→} from "@xyflow/react";
  8→
  9→export interface EdgeConditionData {
 10→  condition?: string;
 11→  onConditionChange?: (edgeId: string, condition: string) => void;
 12→  [key: string]: unknown;
 13→}
 14→
 15→type EdgeWithConditionProps = EdgeProps<Edge<EdgeConditionData>>;
 16→
 17→function abbreviate(text: string, max = 20): string {
 18→  if (text.length <= max) return text;
 19→  return text.slice(0, max) + "…";
 20→}
 21→
 22→export function EdgeWithCondition({
 23→  id,
 24→  sourceX,
 25→  sourceY,
 26→  targetX,
 27→  targetY,
 28→  sourcePosition,
 29→  targetPosition,
 30→  selected,
 31→  data,
 32→  markerEnd,
 33→}: EdgeWithConditionProps) {
 34→  const [edgePath, labelX, labelY] = getBezierPath({
 35→    sourceX,
 36→    sourceY,
 37→    targetX,
 38→    targetY,
 39→    sourcePosition,
 40→    targetPosition,
 41→  });
 42→
 43→  const condition = data?.condition ?? "";
 44→  const onConditionChange = data?.onConditionChange;
 45→
 46→  const [editing, setEditing] = useState(false);
 47→  const [draft, setDraft] = useState(condition);
 48→  const inputRef = useRef<HTMLInputElement>(null);
 49→
 50→  // Sync draft when external condition changes
 51→  useEffect(() => {
 52→    if (!editing) {
 53→      setDraft(condition);
 54→    }
 55→  }, [condition, editing]);
 56→
 57→  // Focus input when entering edit mode
 58→  useEffect(() => {
 59→    if (editing) {
 60→      inputRef.current?.focus();
 61→      inputRef.current?.select();
 62→    }
 63→  }, [editing]);
 64→
 65→  const handleLabelClick = useCallback(
 66→    (e: React.MouseEvent) => {
 67→      e.stopPropagation();
 68→      setEditing(true);
 69→    },
 70→    [],
 71→  );
 72→
 73→  const commitEdit = useCallback(() => {
 74→    setEditing(false);
 75→    const trimmed = draft.trim();
 76→    if (trimmed !== condition) {
 77→      onConditionChange?.(id, trimmed);
 78→    }
 79→  }, [draft, condition, onConditionChange, id]);
 80→
 81→  const handleKeyDown = useCallback(
 82→    (e: React.KeyboardEvent) => {
 83→      if (e.key === "Enter") {
 84→        commitEdit();
 85→      } else if (e.key === "Escape") {
 86→        setDraft(condition);
 87→        setEditing(false);
 88→      }
 89→    },
 90→    [commitEdit, condition],
 91→  );
 92→
 93→  const edgeColor = selected ? "#3B82F6" : "#6b7280";
 94→
 95→  return (
 96→    <>
 97→      <BaseEdge
 98→        path={edgePath}
 99→        markerEnd={markerEnd}
100→        style={{ stroke: edgeColor, strokeWidth: 2 }}
101→      />
102→
103→      <foreignObject
104→        x={labelX - 100}
105→        y={labelY - 14}
106→        width={200}
107→        height={28}
108→        requiredExtensions="http://www.w3.org/1999/xhtml"
109→        style={{ overflow: "visible", pointerEvents: "none" }}
110→      >
111→        <div
112→          style={{
113→            display: "flex",
114→            justifyContent: "center",
115→            alignItems: "center",
116→            width: "100%",
117→            height: "100%",
118→            pointerEvents: "all",
119→          }}
120→        >
121→          {editing ? (
122→            <input
123→              ref={inputRef}
124→              value={draft}
125→              onChange={(e) => setDraft(e.target.value)}
126→              onBlur={commitEdit}
127→              onKeyDown={handleKeyDown}
128→              placeholder='outputs["accuracy"] > 0.8'
129→              style={{
130→                fontFamily: "monospace",
131→                fontSize: "12px",
132→                padding: "2px 6px",
133→                background: "rgba(30, 30, 34, 0.9)",
134→                color: "#e4e4e7",
135→                border: "1px solid #3B82F6",
136→                borderRadius: "4px",
137→                outline: "none",
138→                width: "200px",
139→                textAlign: "center",
140→              }}
141→            />
142→          ) : condition ? (
143→            <span
144→              onClick={handleLabelClick}
145→              style={{
146→                fontFamily: "monospace",
147→                fontSize: "11px",
148→                color: "#9ca3af",
149→                background: "rgba(30, 30, 34, 0.8)",
150→                padding: "1px 6px",
151→                borderRadius: "3px",
152→                cursor: "pointer",
153→                whiteSpace: "nowrap",
154→                userSelect: "none",
155→              }}
156→            >
157→              {abbreviate(condition)}
158→            </span>
159→          ) : selected ? (
160→            <span
161→              onClick={handleLabelClick}
162→              style={{
163→                fontFamily: "monospace",
164→                fontSize: "11px",
165→                color: "#6b7280",
166→                background: "rgba(30, 30, 34, 0.8)",
167→                padding: "1px 6px",
168→                borderRadius: "3px",
169→                cursor: "pointer",
170→                whiteSpace: "nowrap",
171→                userSelect: "none",
172→              }}
173→            >
174→              + condition
175→            </span>
176→          ) : null}
177→        </div>
178→      </foreignObject>
179→    </>
180→  );
181→}
