  1→import { memo } from "react";
  2→import { Handle, Position, type NodeProps, type Node } from "@xyflow/react";
  3→import { Button } from "@/components/ui/button";
  4→import {
  5→  type NodeDefinition,
  6→  type NodeStatus,
  7→  type PortType,
  8→  PORT_COLORS,
  9→} from "@/lib/types";
 10→
 11→const STATUS_COLORS: Record<string, string> = {
 12→  idle: "#D1D5DB",
 13→  pending: "#D1D5DB",
 14→  running: "#3B82F6",
 15→  done: "#22C55E",
 16→  error: "#EF4444",
 17→  skipped: "#F59E0B",
 18→};
 19→
 20→export type NodeTab = "params" | "code" | "output";
 21→
 22→export interface NodeCardData {
 23→  label: string;
 24→  definition: NodeDefinition;
 25→  status: NodeStatus | "idle";
 26→  params: Record<string, string | number | boolean>;
 27→  onTabClick?: (nodeId: string, tab: NodeTab) => void;
 28→  [key: string]: unknown;
 29→}
 30→
 31→type NodeCardNode = Node<NodeCardData, "nodeCard">;
 32→
 33→function PortBadge({ type }: { type: PortType }) {
 34→  return (
 35→    <span
 36→      className="rounded px-1 py-0.5 text-[10px] font-medium leading-none text-white"
 37→      style={{ backgroundColor: PORT_COLORS[type] }}
 38→    >
 39→      {type}
 40→    </span>
 41→  );
 42→}
 43→
 44→function NodeCardComponent({
 45→  id,
 46→  data,
 47→  selected,
 48→}: NodeProps<NodeCardNode>) {
 49→  const { label, definition, status, onTabClick } = data;
 50→  const statusColor = STATUS_COLORS[status] ?? STATUS_COLORS.idle;
 51→  const isRunning = status === "running";
 52→
 53→  return (
 54→    <div
 55→      className="min-w-[200px] rounded-lg bg-white shadow"
 56→      style={{
 57→        border: selected ? "2px solid #3B82F6" : "1px solid #E5E7EB",
 58→      }}
 59→      onClick={() => onTabClick?.(id, "params")}
 60→    >
 61→      {/* Header */}
 62→      <div className="flex items-center justify-between border-b border-[#E5E7EB] px-3 py-2">
 63→        <span className="text-sm font-medium text-gray-900">{label}</span>
 64→        <span
 65→          className={`inline-block h-2 w-2 rounded-full${isRunning ? " animate-pulse" : ""}`}
 66→          style={{ backgroundColor: statusColor }}
 67→        />
 68→      </div>
 69→
 70→      {/* Ports */}
 71→      <div className="relative px-3 py-2">
 72→        {/* Input ports (left side) */}
 73→        {definition.inputs.map((port) => (
 74→          <div
 75→            key={`in-${port.name}`}
 76→            className="relative flex items-center gap-1.5 py-0.5"
 77→          >
 78→            <Handle
 79→              type="target"
 80→              position={Position.Left}
 81→              id={port.name}
 82→              className="!-left-[9px] !h-3 !w-3 !rounded-full !border-2 !border-white"
 83→              style={{ backgroundColor: PORT_COLORS[port.type], top: "auto" }}
 84→            />
 85→            <span className="text-xs text-gray-600">{port.name}</span>
 86→            <PortBadge type={port.type} />
 87→          </div>
 88→        ))}
 89→
 90→        {/* Output ports (right side) */}
 91→        {definition.outputs.map((port) => (
 92→          <div
 93→            key={`out-${port.name}`}
 94→            className="relative flex items-center justify-end gap-1.5 py-0.5"
 95→          >
 96→            <PortBadge type={port.type} />
 97→            <span className="text-xs text-gray-600">{port.name}</span>
 98→            <Handle
 99→              type="source"
100→              position={Position.Right}
101→              id={port.name}
102→              className="!-right-[9px] !h-3 !w-3 !rounded-full !border-2 !border-white"
103→              style={{ backgroundColor: PORT_COLORS[port.type], top: "auto" }}
104→            />
105→          </div>
106→        ))}
107→
108→        {definition.inputs.length === 0 && definition.outputs.length === 0 && (
109→          <div className="py-1 text-xs text-gray-400">No ports</div>
110→        )}
111→      </div>
112→
113→      {/* Footer - tab buttons */}
114→      <div className="flex border-t border-[#E5E7EB]">
115→        {(["params", "code", "output"] as NodeTab[]).map((tab) => (
116→          <Button
117→            key={tab}
118→            variant="ghost"
119→            size="xs"
120→            className="flex-1 rounded-none text-[11px] capitalize text-gray-500 hover:bg-gray-50 hover:text-gray-900"
121→            onClick={(e) => {
122→              e.stopPropagation();
123→              onTabClick?.(id, tab);
124→            }}
125→          >
126→            {tab === "params" ? "Params" : tab === "code" ? "Code" : "Output"}
127→          </Button>
